CREATE TABLE questions_to_systems
(
	id serial,
	question_id integer NOT NULL,
	system_id integer DEFAULT NULL,
	CONSTRAINT pk_questions_to_systems PRIMARY KEY (id)
	, CONSTRAINT fk_questions_to_systems_to_question FOREIGN KEY (question_id) REFERENCES qualitative_questions (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_questions_to_systems_to_system FOREIGN KEY (system_id) REFERENCES systems (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_questions_to_systems_question ON questions_to_systems (question_id);
CREATE INDEX i_questions_to_systems_system ON questions_to_systems (system_id);
